// Format agent response + save conversation to session_state DataTable
const input = $input.first().json;
const ip = $("Intent Parser").first().json;
const prep = $("Prepare Agent Input").first().json;
const chatId = ip.chat_id;
const sessionKey = prep._session?.key || `tg_${chatId}`;
const sessionRowId = prep._session?.rowId;
const N8N_BASE = 'https://mmurawala.app.n8n.cloud';
const N8N_API_KEY = $vars.N8N_API_KEY;
const SESSION_TABLE = '2z5zRvsJZsGBtsmw';
const MAX_HISTORY = 20;

if (input.error || (typeof input.message === 'string' && input.message.includes('error'))) {
  return [{ json: { chat_id: chatId, text: 'Agent error. Try again.\n' + (input.error || input.message || 'Unknown').toString().substring(0, 200) } }];
}
let text = input.response || input.data?.response || 'No response from agent.';
if (text.length > 4000) text = text.substring(0, 3997) + '...';

let history = [];
try { history = prep.context?.history || []; } catch(e) { history = []; }
history.push({ role: 'user', content: ip.goal });
history.push({ role: 'assistant', content: text });
if (history.length > MAX_HISTORY) history = history.slice(-MAX_HISTORY);

const now = new Date().toISOString();
try {
  if (sessionRowId) {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${N8N_BASE}/api/v1/data-tables/${SESSION_TABLE}/rows/${sessionRowId}`,
      headers: { 'X-N8N-API-KEY': N8N_API_KEY, 'Content-Type': 'application/json' },
      body: { state: JSON.stringify(history), updated_at: now },
      json: true
    });
  } else {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${N8N_BASE}/api/v1/data-tables/${SESSION_TABLE}/rows`,
      headers: { 'X-N8N-API-KEY': N8N_API_KEY, 'Content-Type': 'application/json' },
      body: { session_id: sessionKey, model: 'telegram', state: JSON.stringify(history), updated_at: now },
      json: true
    });
  }
} catch(e) { /* session save failed, non-critical */ }

return [{ json: { chat_id: chatId, text } }];

// Load conversation history from session_state DataTable, then prepare agent input
const ip = $("Intent Parser").first().json;
const chatId = ip.chat_id;
const sessionKey = `tg_${chatId}`;
const N8N_BASE = 'https://mmurawala.app.n8n.cloud';
const N8N_API_KEY = $vars.N8N_API_KEY;
const SESSION_TABLE = '2z5zRvsJZsGBtsmw';
const SESSION_TTL_MS = 30 * 60 * 1000;
const MAX_HISTORY = 20;

let history = [];
let sessionRowId = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${N8N_BASE}/api/v1/data-tables/${SESSION_TABLE}/rows?limit=250`,
    headers: { 'X-N8N-API-KEY': N8N_API_KEY },
    json: true
  });
  const rows = resp.data || resp.rows || [];
  const row = rows.find(r => r.session_id === sessionKey);
  if (row) {
    sessionRowId = row.id;
    const updatedAt = new Date(row.updated_at || 0).getTime();
    const now = Date.now();
    if (now - updatedAt < SESSION_TTL_MS) {
      try { history = JSON.parse(row.state || '[]'); } catch(e) { history = []; }
      if (history.length > MAX_HISTORY) history = history.slice(-MAX_HISTORY);
    } else {
      history = [];
    }
  }
} catch(e) { /* session load failed, proceed without history */ }

return [{ json: {
  goal: ip.goal,
  tenant_id: ip.tenant_id,
  context: { history },
  _session: { key: sessionKey, rowId: sessionRowId, chat_id: chatId }
} }];
